  @HostListener('document:mousemove', ['$event'])
  onMouseMove(e) {
    let o = this.eyes[0].x - e.x;
    let a = this.eyes[0].y - e.y;

    let p = this.get_point_between_points(this.eyes[0], e, 6);

    this.eyes[0].transform = `translateX(${
      p[0] - this.eyes[0].x
    }%) translateY(${p[1] - this.eyes[0].y}%)`;

    o = this.eyes[1].x - e.x;
    a = this.eyes[1].y - e.y;
    p = this.get_point_between_points(this.eyes[1], e, 6);
    this.eyes[1].transform = `translateX(${
      p[0] - this.eyes[1].x
    }%) translateY(${p[1] - this.eyes[1].y}%)`;
    const p2 = this.get_point_between_points(this.eyes[1], e, 120);
  }

  get_point_between_points(p1, p2, distance) {
    let dist_btw_points = Math.sqrt((p2.x - p1.x) ** 2 + (p2.y - p1.y) ** 2);
    let distance_ratio = distance / dist_btw_points;
    let x = p1.x + distance_ratio * (p2.x - p1.x);
    let y = p1.y + distance_ratio * (p2.y - p1.y);
    return [x, y];
  }

  getHypotinuse(a, b) {
    return Math.sqrt(Math.pow(a, 2) + Math.pow(b, 2));
  }

